insert into public.jokes (lang, category, text, sort_order) values
  ('en', 'burger', 'The Red Hulk is double aloo patty energy. It does not smash buildings, just your small hunger plans.', 0),
  ('en', 'food', 'Our patties are house-made because frozen patties do not understand commitment.', 1),
  ('en', 'wait', 'Choosing from this menu counts as cardio for your brain.', 2),
