  ('en', 'dad', 'I tried to make a sandwich laugh, but it was too pressed.', 36),
  ('en', 'food', 'A good meal does not ask questions. It answers them.', 37),
  ('en', 'desi', 'There are two desi settings: just ate and still looking for something small.', 38),
