  ('en', 'desi', 'In a desi house, leftovers are not leftovers. They are tomorrow''s comeback story.', 47),
  ('en', 'wait', 'You are not impatient. You are just emotionally invested in lunch.', 48),
  ('en', 'food', 'Good food does not need a speech. It just needs one silent first bite.', 49),
  ('en', 'dad', 'Why did the pickle stay calm? It was already in a jar of peace.', 50),
